import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { authAPI } from '../services/api';
import { StatCard, Card, Badge, Button, PageHeader, EmptyState } from '../components/ui';
import { Database, Leaf, FolderOpen, Link2, ArrowRight, Zap, Clock, CheckCircle } from 'lucide-react';
import './DashboardPage.css';

const QUICK_ACTIONS = [
  { label: 'PostgreSQL Query', desc: 'Ask your PostgreSQL database anything', icon: Database, color: 'blue', to: '/query/postgres' },
  { label: 'MongoDB Query',    desc: 'Query MongoDB collections naturally',   icon: Leaf,     color: 'green', to: '/query/mongo' },
  { label: 'My Datasets',      desc: 'Upload & query CSV and Excel files',    icon: FolderOpen,color:'purple',to: '/datasets' },
  { label: 'Connections',      desc: 'Manage your saved DB connections',      icon: Link2,    color: 'amber', to: '/connections' },
];

const TIPS = [
  'Try: "Show me total revenue by region for last 3 months"',
  'Try: "Which customers have the highest lifetime value?"',
  'Try: "Find products with low stock across all warehouses"',
  'Try: "Show monthly sales trend for the past year"',
];

export default function DashboardPage() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [connections, setConnections] = useState([]);
  const [tipIdx] = useState(() => Math.floor(Math.random() * TIPS.length));

  useEffect(() => {
    authAPI.connections()
      .then(r => setConnections(r.data || []))
      .catch(() => {});
  }, []);

  const pgConns    = connections.filter(c => c.db_type === 'postgresql');
  const mongoConns = connections.filter(c => c.db_type === 'mongodb');
  const greeting   = () => {
    const h = new Date().getHours();
    if (h < 12) return 'Good morning';
    if (h < 17) return 'Good afternoon';
    return 'Good evening';
  };

  return (
    <div className="dashboard fade-in">
      {/* ── Greeting ────────────────────────────────────── */}
      <div className="dash-greeting">
        <div>
          <h1 className="dash-greeting-title">
            {greeting()}, {user?.username} 👋
          </h1>
          <p className="dash-greeting-sub">
            What would you like to explore today?
          </p>
        </div>
        <div className="dash-tip">
          <span className="dash-tip-label"><Zap size={12} /> Tip</span>
          <span className="dash-tip-text">{TIPS[tipIdx]}</span>
        </div>
      </div>

      {/* ── Stats ───────────────────────────────────────── */}
      <div className="dash-stats">
        <StatCard
          label="PostgreSQL Connections"
          value={pgConns.length}
          icon={<Database size={18} />}
          color="blue"
          delta={pgConns.length ? `${pgConns.map(c=>c.name||c.db_name).join(', ')}` : 'No connections yet'}
        />
        <StatCard
          label="MongoDB Connections"
          value={mongoConns.length}
          icon={<Leaf size={18} />}
          color="green"
          delta={mongoConns.length ? `${mongoConns.map(c=>c.name||c.db_name).join(', ')}` : 'No connections yet'}
        />
        <StatCard
          label="Total Connections"
          value={connections.length}
          icon={<Link2 size={18} />}
          color="purple"
          delta="Across all database types"
        />
        <StatCard
          label="AI Pipeline"
          value="Active"
          icon={<CheckCircle size={18} />}
          color="teal"
          delta="Gemini 2.0 Flash · 8 agents"
        />
      </div>

      {/* ── Quick Actions ────────────────────────────────── */}
      <div className="dash-section">
        <h2 className="dash-section-title">Quick Actions</h2>
        <div className="dash-actions">
          {QUICK_ACTIONS.map(({ label, desc, icon: Icon, color, to }) => (
            <button key={to} className={`dash-action-card dash-action-${color}`} onClick={() => navigate(to)}>
              <div className={`dash-action-icon`}>
                <Icon size={20} />
              </div>
              <div className="dash-action-body">
                <div className="dash-action-label">{label}</div>
                <div className="dash-action-desc">{desc}</div>
              </div>
              <ArrowRight size={16} className="dash-action-arrow" />
            </button>
          ))}
        </div>
      </div>

      {/* ── Setup prompt if no connections ──────────────── */}
      {connections.length === 0 && (
        <Card className="dash-setup-card">
          <div className="dash-setup-content">
            <div className="dash-setup-icon"><Link2 size={24} /></div>
            <div>
              <div className="dash-setup-title">Connect your first database</div>
              <div className="dash-setup-desc">
                Add a PostgreSQL or MongoDB connection to start querying with AI.
              </div>
            </div>
            <Button onClick={() => navigate('/connections')} icon={<ArrowRight size={15} />}>
              Add Connection
            </Button>
          </div>
        </Card>
      )}

      {/* ── How it works ─────────────────────────────────── */}
      <div className="dash-section">
        <h2 className="dash-section-title">How it works</h2>
        <div className="dash-pipeline">
          {[
            { step: '01', title: 'Type a question', desc: 'Ask anything in plain English — no SQL needed', color: 'blue' },
            { step: '02', title: 'Gemini reads your schema', desc: 'AI understands your tables, columns & relationships', color: 'purple' },
            { step: '03', title: 'SQL is generated & verified', desc: 'Safety-checked before touching your database', color: 'amber' },
            { step: '04', title: 'Results + AI insights', desc: 'Tables, charts, and EDA analysis instantly', color: 'green' },
          ].map(({ step, title, desc, color }) => (
            <div key={step} className={`dash-pipe-step dash-pipe-${color}`}>
              <div className="dash-pipe-num">{step}</div>
              <div className="dash-pipe-title">{title}</div>
              <div className="dash-pipe-desc">{desc}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
